import { mkdirSync, writeFileSync } from 'node:fs'
import { resolve } from 'node:path'
import { productsCatalog } from '../shared/dist/catalog/products.js'

const outputDir = resolve('deploy/nginx')
const outputPath = resolve(outputDir, 'product-id-redirects.conf')

const redirectRules = productsCatalog
  .filter((product) => product.id !== product.slug)
  .map((product) => `location = /product/${product.id} { return 301 /product/${product.slug}$is_args$args; }`)

const fileContent = [
  '# Generated by scripts/generate-product-redirects.mjs',
  '# Include this file inside `server { ... }` block in nginx config.',
  ...redirectRules,
  '',
].join('\n')

mkdirSync(outputDir, { recursive: true })
writeFileSync(outputPath, fileContent, 'utf8')

console.log(`Generated nginx redirects: ${outputPath} (${redirectRules.length} rules)`)
